('old-data-berta2-all-20260501-01', 'recgJDh7FHNgbmoP6', 'max_capacity', '6', 'Berta 2.0', U&'{"id":"recgJDh7FHNgbmoP6","Nom commercial":"MY HOME Villa","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Le Tampon","Adresse":"250  Rue Maurice et Katia Krafft, 97418 Le Tampon - La Plaine des Cafres","Site web":"","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Location saisonni\00E8re","Nom sous cat\00E9gorie":"G\00EEte & Villa","Localisations":"","Code postal":"97418","Bureau postal":"La Plaine des Cafres","Lieux-dits":"La Plaine des Cafres","Prestations sur place":"chauffage , jardin , parking , wifi , cuisine \00E9quip\00E9e , salon , barbecue , four , TV , fer et planche \00E0 repasser , jacuzzi , vue montagne , linge de maison , lave vaisselle , linge de toilette , frigo , s\00E8che-cheveux , bouilloire , chemin\00E9e","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,commerce alimentaire,\00E9quitation,point de vue panoramique,sentier de grande randonn\00E9e","Mode de paiement":"airbnb,site internet","Langues":"Fran\00E7ais,anglais,cr\00E9ole","Fixe":"","Mobile":"0692687996","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"ticazloc@orange.fr ","Capacit\00E9":"6","Classement":"","Accroche":"My Home Villa","Descriptif":"La villa dispose de 3 chambres avec chacune sa salle d''eau, pr\00E9servant l''intimit\00E9 de chaque personne.\\n\\nChambre 1 : 1 lit double\\nChambre 2 : 1 lit double\\nChambre 3 : 2 lits simples\\n\\nLa pi\00E8ce principale est compl\00E8tement ouverte sur l''ext\00E9rieur donnant ainsi une clart\00E9 et une sensation de \\"vie en plein air \\".\\n\\nLe rev\00EAtement ext\00E9rieur est compos\00E9 essentiellement de scories volcaniques ( lave refroidie, l\00E9g\00E8re et fragment\00E9e) typique au charme de la r\00E9gion. La Maison du Volcan est \00E0 5 minutes \00E0 pieds.\\n\\nUne cuisine ext\00E9rieure est \00E0 votre disposition pour vos repas et grillades...Des tables et fauteuils de jardin \00E9galement.\\n\\nPour passer le temps un mini espace de p\00E9tanque est mis \00E0 votre disposition et enfin pour vous relaxer apr\00E8s vos randonn\00E9es, un jacuzzi vous est propos\00E9 pour une capacit\00E9 de 5 personnes ( 2 places allong\00E9es et 3 assises ).","Descriptif du plan d''acc\00E8s":"Plaine des cafres","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"","Date de fermeture":"","Fournisseur - Nom":"Mr Jean Laurent Oussenekan","Fournisseur - SIRET":"","Fournisseur - adresse":"Mr Jean Laurent Oussenekan: 250 Rue Maurice et Katia Krafft, 97418 La Plaine des Cafres","Fournisseur - contacts":"ticazloc@orange.fr / 0692687996","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.198116, 55.577736","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"CSC415HT@","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"AD2R","source_system":"berta_v2_csv_export"}', 'pending', 'true'),
('old-data-berta2-all-20260501-01', 'reco2MfzJdwyiquYE', 'max_capacity', '14', 'Berta 2.0', U&'{"id":"reco2MfzJdwyiquYE","Nom commercial":"Le P''tit Paille en Queue ","Raison sociale":"","Motif Hors ligne":"","En ligne":"oui","Zone":"sud","Nom de la commune":"Le Tampon","Adresse":"87 T Chemin Notre-Dame-de-la-Paix, 97418 Le Tampon - La Plaine des Cafres","Site web":"https://www.locationplainedescafres.com/pages/coordonnees.html#:~:text=LOCATION%20SAISONNIERE%20LE%20P''TIT%20PAILLE%20EN%20QUEUE,-%3F&text=Pour%20vos%20moments%20de%20d%C3%A9tente,est%20de%2014%20personnes%20maximum.","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Location saisonni\00E8re","Nom sous cat\00E9gorie":"Maison","Localisations":"Village des Hauts","Code postal":"97418","Bureau postal":"La Plaine des Cafres","Lieux-dits":"La Plaine des Cafres","Prestations sur place":"Cafeti\00E8re , micro-ondes , cuisine \00E9quip\00E9e , cuisine au bois , cuisine ext\00E9rieur , salon , salle \00E0 manger , salon de jardin , salle de bain , espace de restauration en ext\00E9rieur , billard , babyfoot , dortoir","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,\00E9quitation,point de vue panoramique,for\00EAt,arr\00EAt bus,station service,Maison du Volcan","Mode de paiement":"Esp\00E8ces,site internet,Le bon coin,Ch\00E8que,Virement","Langues":"Fran\00E7ais,cr\00E9ole","Fixe":"0262590366","Mobile":"","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"rivierepailleenqueue.974@gmail.com","Capacit\00E9":"14","Classement":"2 Etoile(s)","Accroche":"Maison Le p''tit paille en queue","Descriptif":"La maison comprend 4 chambres de 1 grand lit et un lit superpos\00E9.\\nUn lit parapluie est disponible pour b\00E9b\00E9\\n\\nPour le cot\00E9 pratique et am\00E9liorer votre confort, 2 salles de bain et 2 WC ont \00E9t\00E9 pr\00E9vus.\\n\\nElle est enti\00E8rement \00E9quip\00E9e : cuisini\00E8re, four, four micro onde, r\00E9frig\00E9rateur, cong\00E9lateur, marmite \00E0 riz, cafeti\00E8re (sens\00E9o et classique), vaisselles, ustensiles de cuisine, TV et d\00E9codeur Parabole, barbecue, etc....\\n\\nMerci de noter qu''il n''y a pas de wifi\\n\\nLa cuisine ext\00E9rieure vous permettra au choix de cuisiner un bon carry au feu de bois ou \00E0 gaz (2 feux tripatte)\\n\\nUne table de Ping-Pong, billard et un Babby Foot vous attendent pour passer des agr\00E9ables moments.\\n\\nLes couettes et les couvertures sont fournies.\\nLe linge de lit et de toilette sont disponibles pour ceux qui le souhaitent avec suppl\00E9ment.\\n\\nTARIF TTC (y compris taxe de s\00E9jour et sans forfait linge de lit)\\n- Jusqu''\00E0 9 personnes : 320 \20AC pour 2 nuits (weekend ou en semaine) et 680 \20AC la semaine compl\00E8te ou 6 nuits. (vous avez acc\00E8s \00E0 3 chambres uniquement). Si vous voulez les 4 chambres, le tarif sera de 420 \20AC.\\nNuit suppl\00E9mentaire : 110 \20AC\\n\\n- De 10 \00E0 14 pers maxi ou 4 chambres : 420 \20AC pour 2 nuits (weekend ou en semaine) et 820 \20AC la semaine compl\00E8te ou 6 nuits \\nNuit suppl\00E9mentaire : 150 \20AC\\n\\nFacultatif : Forfait draps \00E0 50 \20AC et forfait serviettes \00E0 30 \20AC\\nLa location pour une seule nuit sera accord\00E9e de fa\00E7on exceptionnelle : 200 \20AC (3 chambres, 9 pers max) et 300 \20AC (4 chambres, 14 pers max).\\n\\nLa remise des cl\00E9s se fait \00E0 partir de 14 h et la sortie au plus tard \00E0 17h\\nPour toute r\00E9servation, il faudra verser un acompte de 30 % minimum. Le solde est \00E0 r\00E9gler au plus tard lors de la r\00E9ception des cl\00E9s.\\nUne caution de 300 \20AC minimum sera demand\00E9e lors de la r\00E9ception des cl\00E9s.\\n\\nDes frais de m\00E9nage de 50 \20AC seront imput\00E9s sur la caution si le nettoyage n''est pas satisfaisant.","Descriptif du plan d''acc\00E8s":"\\"Le p''tit Paille en Queue\\" qui se situe \00E0 la Plaine des Cafres, chemin Notre Dame de la Paix, Petite Ferme.","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etabliss