('old-data-berta2-all-20260501-01', '9a8f7c6d', 'seats', '20', 'Berta 2.0', U&'{"id":"9a8f7c6d","Nom commercial":"Casa Trattoria 23","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Le Tampon","Adresse":"40A chemin Notre Dame de la Paix, 97418 Le Tampon - La Plaine des Cafres","Site web":"","Groupe cat\00E9gorie":"Restauration","Nom cat\00E9gorie":"Restaurant","Nom sous cat\00E9gorie":"Restaurant","Localisations":"Milieu rural","Code postal":"97418","Bureau postal":"La Plaine des Cafres","Lieux-dits":"La Plaine des Cafres","Prestations sur place":"repas originaux et traditionnels , repas du soir sur r\00E9servation , espace de restauration , restauration , espace de restauration en ext\00E9rieur , sur r\00E9servation","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,parking public,point de vue panoramique,station service,Maison du Volcan","Mode de paiement":"Carte Bancaire,Esp\00E8ces,Virement","Langues":"fran\00E7ais,anglais,italien,espagnol","Fixe":"","Mobile":"0692 00 87 91","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"maisoncouleurvolcan2@gmail.com","Capacit\00E9":"20","Classement":"","Accroche":"Une cuisine maison aux saveurs r\00E9unionnaises et italiennes","Descriptif":"La Maison Couleur Volcan vous invite \00E0 sa table d''h\00F4te pour une exp\00E9rience gustative authentique, entre terroir cr\00E9ole et inspiration italienne. Nos plats sont cuisin\00E9s sur place avec des produits locaux,  dans un esprit de partage et de convivialit\00E9.\\n\\nLa Table est disponible 7j/7 \00E0 la client\00E8le de la Chambre\\n\26A0\FE0FLe restaurant pour les personnes ext\00E9rieurs (voir horaires et jours d''ouverture)\\n\\n\\nUn menu qui allie tradition et originalit\00E9\\nVous y trouverez :\\n- Des classiques cr\00E9oles : rougail saucisse, cari, poulet boucan\00E9\\n- Nos incontournables lasagnes : b\0153uf, poulet combava, v\00E9g\00E9tariennes safran pei, aux saveurs adapt\00E9es au go\00FBt r\00E9unionnais\\n- Des desserts maison : tiramisu au rhum ou caf\00E9-vanille, panna cotta, g\00E2teau chocolat, tarte aux fruits de saison\\n- Boissons locales, bi\00E8res, ap\00E9ritifs et vins s\00E9lectionn\00E9s","Descriptif du plan d''acc\00E8s":"Plaine des Cafres, Petite-ferme","Jours et horaires d''ouverture":"Vendredi , Samedi","Labels":"","Date de cr\00E9ation - Etablissement":"10/9/2025","Date de fermeture":"","Fournisseur - Nom":"Mr Olivier COUHAULT","Fournisseur - SIRET":"98931265700012","Fournisseur - adresse":"Mr Olivier COUHAULT: 40A chemin Notre Dame de la Paix, 97418 La Plaine des Cafres","Fournisseur - contacts":"maisoncouleurvolcan2@gmail.com / 0693 84 97 73","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.226185, 55.572859","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'pending', 'true'),
('old-data-berta2-all-20260501-01', '5E9276CCD3', 'max_capacity', '4', 'Berta 2.0', U&'{"id":"5E9276CCD3","Nom commercial":"Alexandre DIJOUX - Guide Conf\00E9rencier","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Entre-Deux","Adresse":"147 Chemin de l''Equerre, 97414 Entre-Deux - Entre-Deux","Site web":"","Groupe cat\00E9gorie":"D\00E9couverte","Nom cat\00E9gorie":"Patrimoine culturel","Nom sous cat\00E9gorie":"Visite guid\00E9e","Localisations":"Village","Code postal":"97414","Bureau postal":"Entre-Deux","Lieux-dits":"Entre-Deux","Prestations sur place":"mat\00E9riel pour l''activit\00E9 , visites p\00E9dagogiques , visites guid\00E9es","Prestations \00E0 proximit\00E9":"commerce alimentaire,point de vue panoramique,sentier de grande randonn\00E9e,site - lieu culturel,sites touristiques,office de tourisme","Mode de paiement":"Esp\00E8ces,Virement","Langues":"fran\00E7ais,cr\00E9ole,anglais","Fixe":"","Mobile":"","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"kafelontan@gmail.com","Capacit\00E9":"4","Classement":"","Accroche":"Alexandre DIJOUX - Guide conf\00E9rencier - Caf\00E9 Habitation","Descriptif":"Alexandre propose une visite guid\00E9e du village de l''Entre-Deux \\n\\n\+01F4CDRDV devant la Kaz Tourist''\\nLe tarif est de 10 \20AC par personne pour une dur\00E9e de 1h30\\n\\n\\"Suivre mes pas c''est s''accorder un moment pour d\00E9couvrir un panorama sur plus de 3 si\00E8cles d''\00E9volution architecturale \00E0 la R\00E9union et d\00E9couvrir le peuplement du village cr\00E9ole de l''Entre-Deux\\"\\n\\nGuide conf\00E9rencier depuis 2005, le yab qui parle en lu vous racontera tout sa que la arriver depuis l''\00E8re des pionniers \00E0 la civilisation de la varangue de la hutte \00E0 la case en bois o\00F9 l''\00E2me cr\00E9ole vibre dans cet \00E9crin majestueux au pied du massif du Dimitile. \\n\\nApr\00E8s cette visite seriez vous prompt \00E0 vous demander : \\"aurais-je d\00E9couvert avec Alexandre le plus beau village de la R\00E9union?\\"\\n\\n- \\"Le pav\00E9 est  lanc\00E9 dans la Mare et on s y donne rendez vous.\\"\\n- \\"C'' est le nom du centre ville ! \\"\\n- \\" Pav\00E9 ? \\"\\n- \\" Non \00F4t\00E9 ! La Mare\\"\\n\\nIl y avait plusieurs mares poissonneuses au temps des noirs marrons mais elles ont \00E9t\00E9 ass\00E9ch\00E9es par contre le gosier d Alexandre lui non; alors arrive \00E0 zot !","Descriptif du plan d''acc\00E8s":"RDV devant l''office de tourisme de l''Entre-Deux","Jours et horaires d''ouverture":"Lundi , Mardi , Mercredi , Jeudi , Vendredi , Samedi","Labels":"","Date de cr\00E9ation - Etablissement":"10/9/2025","Date de fermeture":"","Fournisseur - Nom":"Mr Alexandre Dijoux","Fournisseur - SIRET":"81924331200025","Fournisseur - adresse":"Mr Alexandre Dijoux: 147 Chemin de l''Equerre, 97414 Entre-Deux","Fournisseur - contacts":"kafelontan@gmail.com / 0693 05 15 15","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.265828, 55.464337","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'pending', 'true');
